import{_ as a,o as i,c as e,a2 as n}from"./chunks/framework.BflysNKA.js";const b=JSON.parse('{"title":"macOS 环境准备","description":"","frontmatter":{},"headers":[],"relativePath":"beginner/macos-env.md","filePath":"beginner/macos-env.md","lastUpdated":1780486302000}'),t={name:"beginner/macos-env.md"};function l(p,s,h,r,d,o){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="macos-环境准备" tabindex="-1">macOS 环境准备 <a class="header-anchor" href="#macos-环境准备" aria-label="Permalink to &quot;macOS 环境准备&quot;">​</a></h1><p>安装 Claude Code、Codex 等命令行工具之前，需要先准备好命令行工具、Git 和 Node.js。</p><div class="tip custom-block"><p class="custom-block-title">只用 Cherry Studio？</p><p>Cherry Studio 是桌面客户端，不需要命令行环境。直接去 <a href="/beginner/macos-cherry-studio">Cherry Studio 接入</a>。</p></div><h2 id="第-1-步-打开终端" tabindex="-1">第 1 步：打开终端 <a class="header-anchor" href="#第-1-步-打开终端" aria-label="Permalink to &quot;第 1 步：打开终端&quot;">​</a></h2><p>按 <code>Cmd + Space</code> 打开聚焦搜索，输入 <code>终端</code> 或 <code>Terminal</code>，按回车。</p><p>你会看到一个白色（或黑色）的窗口，光标在等你输入命令。后面所有命令都在这里执行。</p><h2 id="第-2-步-安装命令行工具和-git" tabindex="-1">第 2 步：安装命令行工具和 Git <a class="header-anchor" href="#第-2-步-安装命令行工具和-git" aria-label="Permalink to &quot;第 2 步：安装命令行工具和 Git&quot;">​</a></h2><p>macOS 不自带完整的开发工具。执行以下命令安装 Xcode 命令行工具（包含 Git）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">xcode-select</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>系统会弹出一个安装窗口，点击 <strong>安装</strong>，等待完成（可能需要几分钟）。</p><p>安装完成后验证：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>应该输出 <code>git version 2.xx.x</code>。如果提示需要安装 Xcode，说明上一步没完成，重新执行。</p><h2 id="第-3-步-安装-homebrew-推荐" tabindex="-1">第 3 步：安装 Homebrew（推荐） <a class="header-anchor" href="#第-3-步-安装-homebrew-推荐" aria-label="Permalink to &quot;第 3 步：安装 Homebrew（推荐）&quot;">​</a></h2><p>Homebrew 是 macOS 最常用的包管理工具，后面安装 Node.js 时会用到。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">/bin/bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://raw.githubusercontent.com/Homebrew/install/HEAD/install.sh)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>安装过程中会提示输入密码（就是你的 Mac 登录密码），密码不会显示任何字符，直接输完后按回车。</p><div class="tip custom-block"><p class="custom-block-title">国内下载慢？</p><p>Homebrew 官方脚本从 GitHub 下载，国内可能很慢。可以换用镜像：</p><ul><li><a href="https://mirrors.tuna.tsinghua.edu.cn/help/homebrew/" target="_blank" rel="noreferrer">清华镜像安装指南</a></li><li><a href="https://mirrors.ustc.edu.cn/help/brew.git.html" target="_blank" rel="noreferrer">中科大镜像安装指南</a></li></ul></div><p>安装完成后，<strong>按照终端输出的提示</strong>把 Homebrew 加入 PATH。Apple 芯片通常需要执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &#39;eval &quot;$(/opt/homebrew/bin/brew shellenv)&quot;&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/.zshrc</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/.zshrc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>验证：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">brew</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>应该输出版本号（如 <code>Homebrew 4.x.x</code>）。如果提示 <code>command not found: brew</code>，说明 PATH 没有配对，重新执行上面的 <code>echo</code> 和 <code>source</code> 命令。</p><h2 id="第-4-步-安装-node-js" tabindex="-1">第 4 步：安装 Node.js <a class="header-anchor" href="#第-4-步-安装-node-js" aria-label="Permalink to &quot;第 4 步：安装 Node.js&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">不确定要不要装？</p><p>如果你用 Claude Code 的<strong>官方脚本安装</strong>（<code>curl -fsSL https://claude.ai/install.sh | bash</code>）或 Homebrew 安装（<code>brew install --cask claude-code</code>），可以跳过 Node.js。但如果后面还想用 Codex、Gemini CLI 或其他 npm 工具，建议现在就装好。</p></div><p><strong>Homebrew 安装（推荐）：</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> node</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>手动下载安装：</strong></p><p>从 <a href="https://nodejs.cn/download" target="_blank" rel="noreferrer">Node.js 中文站</a> 下载 <code>.pkg</code> 安装包。Apple 芯片（M1/M2/M3/M4）选 <strong>ARM64</strong>，Intel 选 <strong>x64</strong>。</p><p>安装完成后验证：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>应该分别显示版本号。</p><h2 id="第-5-步-设置-npm-国内镜像-推荐" tabindex="-1">第 5 步：设置 npm 国内镜像（推荐） <a class="header-anchor" href="#第-5-步-设置-npm-国内镜像-推荐" aria-label="Permalink to &quot;第 5 步：设置 npm 国内镜像（推荐）&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://registry.npmmirror.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>验证：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>应该输出 <code>https://registry.npmmirror.com/</code>。</p><h2 id="最终检查" tabindex="-1">最终检查 <a class="header-anchor" href="#最终检查" aria-label="Permalink to &quot;最终检查&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>三条都有版本号输出，环境就准备好了。接下来选一个工具开始配置：</p><ul><li>→ <a href="/beginner/macos-claude-code">macOS 接入 Claude Code</a></li><li>→ <a href="/beginner/macos-codex">macOS 接入 Codex</a></li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Homebrew 安装完但 <code>brew</code> 命令不存在？</strong></p><p>Apple 芯片的 Homebrew 装在 <code>/opt/homebrew/bin/</code>，需要手动加 PATH：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &#39;eval &quot;$(/opt/homebrew/bin/brew shellenv)&quot;&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/.zshrc</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/.zshrc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong><code>sudo</code> 密码输不进去？</strong></p><p>macOS 终端输密码时不会显示任何字符（连星号都没有）。直接输完按回车即可。</p><p><strong>npm 安装全局包时报权限错误？</strong></p><p>用 Homebrew 安装的 Node.js 通常不会有这个问题。如果从官网下载安装的，可能需要 <code>sudo</code>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> 包名</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,50)])])}const k=a(t,[["render",l]]);export{b as __pageData,k as default};
